func (sv *XTCPVisitor) processTunnelStartEvents() {
	for {
		select {
		case <-sv.ctx.Done():
			return
		case <-sv.startTunnelCh:
			start := time.Now()
			sv.makeNatHole()
			duration := time.Since(start)

			if duration < 10*time.Second {
				time.Sleep(10*time.Second - duration)
			}
		}
	}
}
